CREATE SCHEMA IF NOT EXISTS "hyundai-ventas";


CREATE TABLE IF NOT EXISTS "hyundai-ventas"."agnMemory" (
  remitente text NOT NULL,
  nombre text,
  etapa varchar(50),
  modelo varchar(50),
  presupuesto text,
  destinatario text,
  resumen_conversacion text,
  created_at timestamp with time zone DEFAULT (now() AT TIME ZONE 'America/Argentina/Salta'::text) NOT NULL,
  updated_at timestamp with time zone DEFAULT (now() AT TIME ZONE 'America/Argentina/Salta'::text) NOT NULL,
  email text,
  apellido text,
  provincia text,
  ciudad text,
  zona_cobertura text,
  subestado text,
  imagenes_enviadas text,
  version text,
  uso_previsto text,
  forma_pago text,
  horario_contacto text,
  prueba_manejo_ofrecida boolean DEFAULT false,
  prueba_manejo_fecha text,
  vehiculo_permuta text,
  PRIMARY KEY (remitente),
  CONSTRAINT "46908_47905_1_not_null" CHECK (remitente IS NOT NULL),
  CONSTRAINT "46908_47905_8_not_null" CHECK (created_at IS NOT NULL),
  CONSTRAINT "46908_47905_9_not_null" CHECK (updated_at IS NOT NULL)
);

-- Data: "agnMemory"
INSERT INTO "hyundai-ventas"."agnMemory" VALUES ('5493874732132', '', 'Desarrollada', 'Staria', '', NULL, 'El cliente preguntó por la Staria Ultimate 4WD, se le mostraron imágenes principal e interior. Luego pidió ver todo el catálogo disponible y se le envió la imagen general con todos los modelos (HB20, HB20S, Creta, Tucson, Santa Fe, Staria), ofreciendo el link del catálogo web. Se le preguntó el uso previsto para orientar la elección.', '2026-07-16T14:57:08.33376+00:00', '2026-07-17T19:10:56.376715+00:00', '', '', '', '', '', '', 'https://agnhyundai.com.ar/wp-content/uploads/2025/07/destacados_garantia.jpg:principal, https://agnhyundai.com.ar/wp-content/uploads/2025/07/destacados_garantia.jpg:interior, https://agnhyundai.com.ar/wp-content/uploads/2026/07/Nuestros-Vehiculos.png:catalogo', 'Ultimate 4WD', '', '', '', 'false', '', '');
INSERT INTO "hyundai-ventas"."agnMemory" VALUES ('5493815760221', 'Juan', 'Cierre', 'HB20', '', NULL, 'El cliente se llama Juan. Mostró interés en el HB20 (hatchback, versión Comfort Plus MT) para uso particular. Provincia Tucumán, ciudad Yerba Buena, modalidad por llamada. Preguntó por precio y financiación, se le explicó que un asesor brinda esos datos. Propuso horario 22hs, rechazado por estar fuera de atención; se le ofreció alternativa desde las 9hs, insistió con las 22hs nuevamente. Ahora rechazó el contacto inmediato (''no gracias no puedo''), se le propuso coordinar otro horario más cómodo, posiblemente por la tarde. Falta definir presupuesto, forma de pago y horario final de contacto.', '2026-07-17T17:25:39.768324+00:00', '2026-07-20T12:29:12.496108+00:00', '', '', 'Tucumán', 'Yerba Buena', 'Norte', '', 'https://agnhyundai.com.ar/wp-content/uploads/2025/07/Hyundai-HB20Sedan-destacados-exterior-frente.jpg:principal,https://agnhyundai.com.ar/wp-content/uploads/2025/07/Hyundai-HB20-destacados-exterior-frente.jpg:principal,https://agnhyundai.com.ar/wp-content/uploads/2025/07/Hyundai-HB20-destacados-renovado-y-moderno.jpg:exterior_lateral', 'Comfort Plus MT', 'Particular', '', '22hs (rechazado varias veces), evaluando horario alternativo por la tarde', 'false', '', '');
INSERT INTO "hyundai-ventas"."agnMemory" VALUES ('5493815635227', 'Gustavo', 'Cierre', 'Creta', '', NULL, 'Gustavo, de Salta, busca un auto familiar para 5 personas. Eligió antes Creta Safety+ y luego Tucson (versiones 1.6 T-GDI Híbrido 4WD HEV y 2.0 Smartstream Nafta 2WD AT), recibiendo imágenes de ambas. Se ofreció visita presencial con test drive en sucursal Pellegrini 1030, pidió tiempo para pensarlo. Preguntó ubicación, café en sucursal, precio (derivado a asesor), catálogo, contacto y nombre de Geni. Preguntó diferencia entre Híbrida 4WD HEV y Nafta 4WD DCT. Preguntó qué modelos vende AGN, se le listaron HB20, HB20S, Creta, Tucson y STARIA con imagen catálogo. Volvió a pedir foto de interior del Creta, se le ofreció interior de Tucson y aceptó verla. Faltan ciudad puntual, presupuesto y forma de pago.', '2026-07-17T12:18:16.999435+00:00', '2026-07-20T19:07:18.241271+00:00', '', '', 'Salta', '', 'Salta', '', 'https://agnhyundai.com.ar/wp-content/uploads/2025/06/3.jpg:principal,https://agnhyundai.com.ar/wp-content/uploads/2025/06/creta25-destacados-espacio-interior-1.jpg:interior,https://agnhyundai.com.ar/wp-content/uploads/2025/06/creta25-destacados-espacioso-y-moderno.jpg:exterior_lateral,https://agnhyundai.com.ar/wp-content/uploads/2025/07/Hyundai-tucson-destacados-botton-cta-disenio.jpg:principal,https://agnhyundai.com.ar/wp-content/uploads/2025/06/Hyundai-tucson-destacados-botton-cta-disenio.jpg:principal,https://agnhyundai.com.ar/wp-content/uploads/2026/07/Nuestros-Vehiculos.png:catalogo,https://agnhyundai.com.ar/wp-content/uploads/2025/06/Hyundai-Tucson-asientos-interior.jpg:asientos', 'Safety+', 'Particular', '', '', 'true', 'lunes 9:30hs (propuesta, pendiente confirmación)', '');
INSERT INTO "hyundai-ventas"."agnMemory" VALUES ('5493815505510', 'Oscar', 'Cierre', 'Creta', 'USD 15000 de entrega + financiación', NULL, 'Oscar reaccionó con entusiasmo a la imagen del interior del Creta (''hermoso!''). Sigue confirmada la llamada del sábado 12hs para avanzar. Datos registrados: USD 15000 de entrega + financiación, Santiago del Estero Capital, zona Norte, atención por llamada, uso particular, forma de pago financiado. Pendiente confirmar si elige la versión Safety +.', '2026-07-17T15:22:13.802365+00:00', '2026-07-17T18:36:35.7613+00:00', 'oscar.greco@gmail.com', '', 'Santiago del Estero', 'Capital', 'Norte', '', 'https://agnhyundai.com.ar/wp-content/uploads/2025/06/3.jpg:principal,https://agnhyundai.com.ar/wp-content/uploads/2025/06/creta25-destacados-espacio-interior-1.jpg:interior', '', 'Particular', 'Financiado', 'Sábado 12hs', 'false', '', '');

CREATE TABLE IF NOT EXISTS "hyundai-ventas".contenido_narrativo (
  id uuid DEFAULT extensions.gen_random_uuid() NOT NULL,
  modelo_id uuid,
  marca text DEFAULT 'Hyundai'::text NOT NULL,
  tipo text NOT NULL,
  titulo text,
  contenido text NOT NULL,
  embedding "hyundai-ventas".vector,
  metadata jsonb,
  source_url text,
  tokens integer,
  vigente_hasta date,
  activo boolean DEFAULT true,
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now(),
  PRIMARY KEY (id),
  CONSTRAINT contenido_narrativo_tipo_check CHECK ((tipo = ANY (ARRAY['descripcion_modelo'::text, 'argumento_venta'::text, 'promocion'::text, 'condiciones_financiacion'::text, 'faq'::text, 'comparativa'::text, 'otro'::text]))),
  CONSTRAINT "46908_48516_1_not_null" CHECK (id IS NOT NULL),
  CONSTRAINT "46908_48516_3_not_null" CHECK (marca IS NOT NULL),
  CONSTRAINT "46908_48516_4_not_null" CHECK (tipo IS NOT NULL),
  CONSTRAINT "46908_48516_6_not_null" CHECK (contenido IS NOT NULL)
);
CREATE INDEX idx_contenido_tipo ON "hyundai-ventas".contenido_narrativo USING btree (tipo);
CREATE INDEX idx_contenido_activo ON "hyundai-ventas".contenido_narrativo USING btree (activo) WHERE (activo = true);
CREATE INDEX idx_contenido_embedding_hnsw ON "hyundai-ventas".contenido_narrativo USING hnsw (embedding vector_cosine_ops);
ALTER TABLE "hyundai-ventas".contenido_narrativo ADD CONSTRAINT contenido_narrativo_modelo_id_fkey FOREIGN KEY (modelo_id) REFERENCES "hyundai-ventas".modelos (id) ON UPDATE NO ACTION ON DELETE SET NULL;

-- Data: contenido_narrativo
INSERT INTO "hyundai-ventas".contenido_narrativo VALUES ('a66037b3-47a0-4582-9c32-f533289b1bc5', 'e31bb0d2-7f4d-4caa-b2a9-becf42a8fde0', 'Hyundai', 'argumento_venta', 'HB20 — seguridad como diferencial', 'Las 3 versiones incluyen 6 airbags de serie. La versión Platinum Safety suma el paquete ADAS completo: frenado autónomo de emergencia, asistente de mantenimiento de carril y alerta de tráfico cruzado trasero — un argumento fuerte para compradores con foco en seguridad familiar.', NULL, NULL, 'https://agnhyundai.com.ar/hb20/', NULL, NULL, 'true', '2026-07-13T14:43:56.710875+00:00', '2026-07-13T14:43:56.710875+00:00');
