INSERT INTO "hyundai-ventas".contenido_narrativo VALUES ('f55928a8-1b51-4ad7-9eb8-02542906771b', 'e2013dc8-8a8e-45cb-a140-479b5da3c45a', 'Hyundai', 'descripcion_modelo', 'STARIA — enfoque general', 'La STARIA es una van premium pensada para quienes necesitan espacio, versatilidad y presencia, ya sea para uso familiar, empresarial o de traslados ejecutivos. Su diseño futurista rompe con todo lo conocido en el segmento, pero lo que más la caracteriza es lo que hay adentro: un habitáculo amplio y confortable, ideal para grupos grandes o cargas voluminosas. Viene con motor 2.2 VGT Diesel de 177 HP y 432 Nm de torque, siempre con caja automática de 8 velocidades, lo que garantiza manejo suave y eficiente tanto en ciudad como en ruta. Está disponible en versión Safety con tracción delantera (2WD), más orientada a uso urbano y confort, y en versión Ultimate con tracción 4WD electrónico (Torque on Demand) más sistema 4x4 lock, pensada para quienes buscan mayor capacidad todo terreno sin resignar equipamiento. Es la opción para el cliente que valora espacio, tecnología y una imagen distinta al resto.', NULL, NULL, NULL, NULL, NULL, 'true', '2026-07-14T12:43:05.064264+00:00', '2026-07-14T12:43:05.064264+00:00');
INSERT INTO "hyundai-ventas".contenido_narrativo VALUES ('b66a1c4e-6712-485a-8094-bd92d2fe8b3b', '4d813870-49e8-4d23-bd13-72399f480857', 'Hyundai', 'descripcion_modelo', 'STARIA — enfoque general', 'La Hyundai STARIA es una van premium pensada para familias grandes, empresas o quienes necesitan trasladar personas con máximo confort y versatilidad. Su diseño futurista rompe con lo tradicional del segmento y ofrece un interior amplio, ideal tanto para uso familiar como para movilidad ejecutiva o corporativa.

Equipa un motor 2.2 VGT Diesel de 177 HP y 432 Nm de torque, con caja automática de 8 velocidades en ambas versiones. La Safety viene con tracción delantera (2WD), pensada para uso urbano y de ruta con eficiencia. La Ultimate suma tracción 4WD electrónica con sistema Torque on Demand y función 4x4 lock, sumando capacidad y seguridad en terrenos exigentes o condiciones climáticas adversas.

Es la opción indicada para quien busca espacio, tecnología y presencia, sin resignar comodidad de manejo. Un vehículo versátil que se adapta tanto a la vida familiar como a necesidades de trabajo o transporte ejecutivo.', NULL, NULL, NULL, NULL, NULL, 'true', '2026-07-14T12:53:31.973187+00:00', '2026-07-14T12:53:31.973187+00:00');
INSERT INTO "hyundai-ventas".contenido_narrativo VALUES ('46345182-a86f-4383-8376-5c9526145cab', '002ba6a3-3cf8-464c-9a81-699775496a49', 'Hyundai', 'descripcion_modelo', 'HB20 — enfoque general', 'El Hyundai HB20 es un hatchback compacto pensado para quienes buscan un auto ágil, moderno y confiable para el uso diario en la ciudad, sin resignar comportamiento en ruta. Está disponible en las versiones Comfort Plus MT, Comfort Plus AT y Platinum Safety AT, todas con motor Gamma 1.6 16V DOHC D-CVVT de 123 HP y 152 Nm de torque, con tracción delantera. El cliente puede elegir transmisión manual o automática de 6 velocidades, según prefiera un manejo más tradicional o mayor comodidad en el tránsito. Es una opción ideal para quien busca su primer auto, para uso familiar en el día a día o para quien necesita un vehículo práctico para moverse por la ciudad con buena respuesta y equipamiento acorde a cada versión. La variante Platinum Safety AT suma un enfoque orientado a la seguridad, siempre dentro de la misma base mecánica.', NULL, NULL, NULL, NULL, NULL, 'true', '2026-07-14T18:25:43.694078+00:00', '2026-07-14T18:25:43.694078+00:00');
INSERT INTO "hyundai-ventas".contenido_narrativo VALUES ('bee73c51-b5e3-4d2a-9597-34458487d123', 'dc6eb495-0d06-4c2d-86f9-6d27000d188f', 'Hyundai', 'descripcion_modelo', 'HB20S — enfoque general', 'El Hyundai HB20S es un sedán compacto pensado para quienes buscan un auto ágil para el uso diario, sin resignar espacio ni equipamiento. Ideal para quien maneja en la ciudad pero también se anima a la ruta con la familia, ofrece un buen equilibrio entre confort, practicidad y respuesta.

Equipa el motor Gamma 1.6 16V DOHC D-CVVT, con 123 HP y 152 Nm de torque, tracción delantera y la posibilidad de elegirlo con caja manual de 6 velocidades (versión Comfort Plus MT) o automática de 6 velocidades (versión Platinum Safety AT), según lo que el cliente prefiera en su día a día.

Es una opción sólida para quien viene de un auto más chico y quiere dar el salto a un sedán con más lugar y prestaciones, sin perder practicidad ni facilidad de manejo.', NULL, NULL, NULL, NULL, NULL, 'true', '2026-07-14T18:28:47.144886+00:00', '2026-07-14T18:28:47.144886+00:00');
INSERT INTO "hyundai-ventas".contenido_narrativo VALUES ('cb985330-8889-46ff-828e-0868156dbc7e', 'b6858778-c4ea-4c44-9298-93ad1b5d4e63', 'Hyundai', 'descripcion_modelo', 'Creta — enfoque general', 'El Hyundai Creta es un SUV pensado para quienes buscan versatilidad, comodidad y un manejo confiable tanto en la ciudad como en rutas cortas. Es ideal para familias o para quienes necesitan un auto con buen espacio interior, altura al piso que da seguridad y una imagen robusta sin perder practicidad en el uso diario.

En la versión Safety +, viene equipado con el motor Smartstream G 1,5lt, 16 válvulas, DOHC, D-CVVT, de 4 cilindros, que entrega 115 HP y 144 Nm de torque, ofreciendo una respuesta ágil y eficiente. Se combina con una transmisión IVT con 8 velocidades preprogramadas, que brinda un manejo suave y progresivo, y tracción delantera, pensada para un uso urbano y confiable.

Es una opción sólida para el cliente que busca dar el salto a un SUV sin resignar practicidad ni presencia en la calle.', NULL, NULL, NULL, NULL, NULL, 'true', '2026-07-14T18:34:20.606796+00:00', '2026-07-14T18:34:20.606796+00:00');
INSERT INTO "hyundai-ventas".contenido_narrativo VALUES ('0673b1ce-9a9b-4a34-b952-91bdce9d5000', 'de741978-5f5d-40ae-928b-e8bd15dabccf', 'Hyundai', 'descripcion_modelo', 'Tucson — enfoque general', 'La Tucson es una SUV mediana pensada para quienes buscan un auto versátil, con presencia y tecnología, tanto para el uso diario en la ciudad como para viajes largos en familia. Hyundai ofrece tres configuraciones bien diferenciadas: una versión 2.0 Smartstream nafta con tracción delantera, ideal para quienes priorizan simpleza y confiabilidad; una versión 1.6 T-GDI con tracción 4WD electrónica y caja doble embrague de 7 velocidades, más orientada a quienes quieren respuesta ágil y seguridad en distintos terrenos; y una versión híbrida 1.6 T-GDI HEV con 230 HP y 367 Nm de torque, la más potente de la gama, sumando eficiencia gracias a su motor eléctrico complementario. En cualquiera de sus versiones, la Tucson se caracteriza por su equilibrio entre diseño moderno, espacio interior y capacidad de adaptarse a distintos estilos de manejo y necesidades del cliente.', NULL, NULL, NULL, NULL, NULL, 'true', '2026-07-14T18:41:39.444546+00:00', '2026-07-14T18:41:39.444546+00:00');
INSERT INTO "hyundai-ventas".contenido_narrativo VALUES ('de69713b-df3d-4088-9d56-e6a99c0b306d', '57e94fe7-e340-4d69-84c0-81b45aff9edf', 'Hyundai', 'descripcion_modelo', 'Tucson — enfoque general', 'La Hyundai Tucson es una SUV mediana pensada para quienes buscan un auto versátil, con presencia y tecnología para el uso diario y también para salir de la ciudad. Está pensada para familias y para quienes necesitan un vehículo con buen espacio interior, comportamiento seguro en ruta y varias configuraciones de motor y tracción según el uso que le quieran dar.

La gama ofrece opciones bien distintas: la versión 2.0 Smartstream con tracción delantera para uso urbano y de ruta liviana, la 1.6 T-GDI Nafta con tracción 4WD electrónica y caja doble embrague de 7 velocidades para quienes buscan más prestaciones y capacidad todo terreno, y la tope de gama 1.6 T-GDI Híbrida con 230 HP, que suma motor eléctrico para más potencia y eficiencia sin perder la tracción 4WD.

Es una SUV ideal para quien quiere un auto completo, moderno y adaptable a distintos estilos de manejo.', NULL, NULL, NULL, NULL, NULL, 'true', '2026-07-14T18:46:38.035667+00:00', '2026-07-14T18:46:38.035667+00:00');
INSERT INTO "hyundai-ventas".contenido_narrativo VALUES ('96b81698-88ac-463b-993a-ecf754865cc0', 'aa6d430f-1b0d-449c-a5aa-9e366dd169db', 'Hyundai', 'descripcion_modelo', 'Tucson — enfoque general', 'La Hyundai Tucson es una SUV mediana pensada para quienes buscan un auto versátil, con presencia y tecnología, tanto para el uso diario en la ciudad como para viajes en familia. Su gama es amplia y se adapta a distintos perfiles: desde el 2.0 Smartstream con tracción delantera, ideal para quienes priorizan simpleza y uso urbano, hasta las versiones 4WD con tracción integral electrónica, pensadas para quienes buscan más seguridad y capacidad en distintos terrenos. La joya de la gama es la versión Híbrida 1.6 T-GDI HEV, que combina motor turbo nafta con motor eléctrico, entregando 230 HP y 367 Nm de torque, ideal para el cliente que busca potencia con eficiencia. La Tucson convence a quienes quieren un auto moderno, tecnológico y con buen equipamiento de seguridad, sin resignar comodidad ni prestaciones.', NULL, NULL, NULL, NULL, NULL, 'true', '2026-07-14T18:47:02.381019+00:00', '2026-07-14T18:47:02.381019+00:00');
INSERT INTO "hyundai-ventas".contenido_narrativo VALUES ('fe6c615e-3ac6-41ef-9592-2c0652ce7e6a', 'de741978-5f5d-40ae-928b-e8bd15dabccf', 'Hyundai', 'descripcion_modelo', 'Tucson — enfoque general', 'La Hyundai Tucson es una SUV mediana pensada para quienes buscan versatilidad, tecnología y presencia, tanto para el uso diario en la ciudad como para viajes largos en familia. Se destaca por su diseño moderno, buen equipamiento y variedad de motorizaciones para distintos perfiles de cliente. Está disponible en versión 2.0 Smartstream nafta con tracción delantera, ideal para quienes priorizan simplicidad y uso urbano; en 1.6 T-GDI nafta con tracción 4WD y caja DCT de 7 velocidades, pensada para quienes quieren más potencia y capacidad todo terreno; y en la tope de gama 1.6 T-GDI Híbrida (HEV) con 230 HP, que suma la fuerza del motor eléctrico a la del turbo para un manejo más eficiente y con mejor respuesta. En los tres casos, la Tucson ofrece tracción 4WD electrónica Torque on Demand (excepto en la 2.0), sumando seguridad y control en distintas condiciones de manejo.', NULL, NULL, NULL, NULL, NULL, 'true', '2026-07-14T18:47:20.417649+00:00', '2026-07-14T18:47:20.417649+00:00');
INSERT INTO "hyundai-ventas".contenido_narrativo VALUES ('9d32b9b6-d8a9-4470-aff3-7410c73ffc01', 'bfdb2324-4193-4288-9520-960c3f9d5a09', 'Hyundai', 'descripcion_modelo', 'HB20 — enfoque general', 'El Hyundai HB20 es un hatchback compacto pensado para quienes buscan un auto ágil, moderno y confiable para el uso diario, ya sea en la ciudad o en rutas cortas. Está dirigido tanto a quien maneja por primera vez un 0km como a familias que necesitan un segundo auto práctico y eficiente. Se destaca por su motor Gamma 1.6 16V DOHC D-CVVT, que entrega 123 HP y 152 Nm de torque, ofreciendo una conducción ágil sin resignar consumo. Está disponible en versiones Comfort Plus, con caja manual o automática de 6 velocidades, y en la versión Platinum Safety con automática de 6 velocidades, pensada para quienes priorizan equipamiento y tecnologías de seguridad. En todos los casos mantiene tracción delantera, ideal para un manejo predecible y estable. Es una opción sólida para el cliente que busca calidad Hyundai, buen respaldo de marca y un auto versátil para el día a día.”', NULL, NULL, NULL, NULL, NULL, 'true', '2026-07-15T16:02:24.523072+00:00', '2026-07-15T16:02:24.523072+00:00');
INSERT INTO "hyundai-ventas".contenido_narrativo VALUES ('371cef5e-e936-4c63-9382-4c755ec38ce5', '002ba6a3-3cf8-464c-9a81-699775496a49', 'Hyundai', 'descripcion_modelo', 'HB20 — enfoque general', 'El HB20 es un hatchback compacto pensado para quienes buscan un auto ágil, moderno y con equipamiento completo para el uso diario en ciudad y en ruta. Está disponible en las versiones Comfort Plus MT, Comfort Plus AT y Platinum Safety AT, todas equipadas con el motor Gamma 1.6 16V DOHC D-CVVT de 123 HP y 152 Nm de torque, con tracción delantera. Las versiones AT ofrecen caja automática de 6 velocidades, ideal para quienes priorizan comodidad y manejo simple en el tránsito diario, mientras que la Comfort Plus MT suma una manual de 6 velocidades para quienes prefieren un manejo más tradicional. Es un auto que combina buen rendimiento, respuesta pareja del motor y una conducción prolija, apuntado a un cliente que busca practicidad, calidad de manejo y la confianza de la marca Hyundai en su día a día.', NULL, NULL, NULL, NULL, NULL, 'true', '2026-07-15T16:02:41.231099+00:00', '2026-07-15T16:02:41.231099+00:00');
INSERT INTO "hyundai-ventas".contenido_narrativo VALUES ('0b8d9d58-da6c-4a77-9022-13df50ca6d65', 'e31bb0d2-7f4d-4caa-b2a9-becf42a8fde0', 'Hyundai', 'descripcion_modelo', 'HB20 — enfoque general', 'El Hyundai HB20 es un hatchback compacto pensado para quienes buscan un auto ágil, moderno y confiable para el uso diario, ya sea en la ciudad o en viajes cortos por ruta. Está equipado con el motor Gamma 1.6 16V DOHC D-CVVT, que entrega 123 HP y 152 Nm de torque, ofreciendo una conducción dinámica y con buena respuesta en distintas situaciones de manejo. Se ofrece en tres versiones: Comfort Plus con caja manual de 6 velocidades, Comfort Plus con automática de 6 velocidades, y Platinum Safety también con transmisión automática de 6 velocidades, todas con tracción delantera. Es una opción ideal para quien busca su primer auto 0km, para familias que necesitan un compacto versátil, o para quienes valoran un equilibrio entre rendimiento, tecnología y respaldo de marca. Un modelo que combina prestaciones sólidas con la calidad y confiabilidad que caracterizan a Hyundai.', NULL, NULL, NULL, NULL, NULL, 'true', '2026-07-15T16:03:20.008969+00:00', '2026-07-15T16:03:20.008969+00:00');

CREATE TABLE IF NOT EXISTS "hyundai-ventas".modelos (
  id uuid DEFAULT extensions.gen_random_uuid() NOT NULL,
  marca text DEFAULT 'Hyundai'::text NOT NULL,
  modelo text NOT NULL,
  version text NOT NULL,
  anio integer,
  precio numeric(14,2),
  moneda text DEFAULT 'ARS'::text,
  vigente_desde date,
  motor text,
  potencia_hp integer,
  torque_nm integer,
  transmision text,
  traccion text,
  consumo_l_100km numeric(5,2),
  equipamiento jsonb,
